import feedparser

def fetch_feed(url):
    feed = feedparser.parse(url)
    return feed

def get_entries(feed):
    return feed.entries

def extract_content(entry):
    content = None
    if entry.content:
        content = entry.content[0].value
    elif entry.summary:
        content = entry.summary
    return content

def get_feeds(urls):
    feeds = []
    for url in urls:
        feed = fetch_feed(url)
        feeds.append(feed)
    return feeds

def get_content(urls):
    feeds = get_feeds(urls)
    entries = []

    for feed in feeds:
        entries.extend(get_entries(feed))

    contents = []
    for entry in entries:
        content = extract_content(entry)
        if content:
            contents.append(content)

    return contents

